import jwt
from Cryptodome import Random, Cipher, PKCS15 as pkcs15

def verify_jwt(token, key, algorithm='HS256'):
    try:
        algorithms = {'HS256': jwt.algorithms.HMAC, 'RS256': jwt.algorithms.RSA}
        alg = algorithms[algorithm]
        decoded_token = alg.verify(token.split('.')[1], key, audience=None, issuer=None, leeway=0)
        return jwt.decode(token, algorithms[algorithm].verkey, algorithms[algorithm].algorithm, issuer=None, audience=None, leeway=0)[1]
    except jwt.ExpiredSignatureError:
        print("Token has expired")
    except jwt.JWTError as ex:
        print(ex)

def load_key(filename):
    with open(filename, 'rb') as key_file:
        return pkcs15.create(key_file)

def generate_jwt(payload, key, algorithm='HS256', expires=None):
    algorithms = {'HS256': jwt.algorithms.HMAC, 'RS256': jwt.algorithms.RSA}
    secret_key = algorithms[algorithm].construct(pkcs15.load_key(key))
    encoded_payload = jwt.encode(payload, secret_key, algorithm=algorithm, encoder=lambda n: n.encode('utf-8'))
    if expires is not None:
        from datetime import timedelta,datetime
        expiration = datetime.utcnow() + timedelta(minutes=expires)
        encoded_payload = jwt.encode(encoded_payload, secret_key, algorithm='HS256', algorithm='none', expires_delta=expiration - datetime.utcnow())
    return encoded_payload